// 传统 CSR — 瀑布式请求
function Dashboard() {
  const [data, setData] = useState(null);

  useEffect(() => {
    // 1. JS 加载完才开始请求
    fetch('/api/dashboard')
      .then(r => r.json())
      .then(setData);
  }, []);

  // 白屏等待...
  if (!data) return <Spinner />;

  return <DashboardUI data={data} />;
}

// React Server Component — 直接访问数据库
async function Dashboard() {
  // 服务器端直接查询，零客户端 JS
  const user = await db.user.findUnique({
    where: { id: session.userId }
  });
  const stats = await analytics.getStats(user.id);
  const notifications = await getNotifications(user.id);

  // 并行获取多个数据源
  const [posts, comments] = await Promise.all([
    db.post.findMany({ where: { authorId: user.id } }),
    db.comment.findMany({ where: { userId: user.id } })
  ]);

  return (
    <DashboardLayout>
      <UserProfile user={user} stats={stats} />
      <PostList posts={posts} />
      <CommentFeed comments={comments} />
    </DashboardLayout>
  );
}

// app/page.tsx — 默认 Server Component
export default async function Page() {
  const data = await fetchData(); // 服务器端
  return <ClientComponent data={data} />;
}

// components/client.tsx
'use client'; // 声明客户端组件
import { useState } from 'react';

export function ClientComponent({ data }) {
  const [active, setActive] = useState(0);
  return <InteractiveUI data={data} />;
}
